-- Q17.	Which age group tends to purchase more premium items?
SELECT age_group, COUNT(*) AS premium_purchases
FROM customer
WHERE purchase_amount > (
    SELECT AVG(purchase_amount) FROM customer
)
GROUP BY age_group
ORDER BY premium_purchases DESC;

