-- Q61.What percentage of customers have active subscriptions?
SELECT 
    ROUND(
        (SUM(CASE WHEN subscription_status = 'Yes' THEN 1 ELSE 0 END) * 100.0) / COUNT(*),
        2
    ) AS subscription_percentage
FROM customer;

